// Read demo transcript file
const fs = require('fs');
const content = fs.readFileSync('/home/node/dataset/demo/bens_electric_demo.txt', 'utf-8');
return [{ json: { content, fileName: 'bens_electric_demo.txt' } }];

// Read onboarding transcript file
const fs = require('fs');
const content = fs.readFileSync('/home/node/dataset/onboarding/bens_electric_onboarding.txt', 'utf-8');
return [{ json: { content, fileName: 'bens_electric_onboarding.txt' } }];

// Extract Account Memo from transcript using LLM-based extraction
const content = $input.item.json.content;
const { extractFromTranscript } = require('/home/node/scripts/extract.js');
const memo = await extractFromTranscript(content, 'demo');
return [{ json: memo }];

// Generate Retell Agent Draft Spec from Account Memo
const { generateAgentSpec } = require('/home/node/scripts/generate-agent-spec.js');
const spec = generateAgentSpec($input.item.json, 'v1');
return [{ json: { memo: $input.item.json, spec } }];

// Store v1 Account Memo JSON
const fs = require('fs');
const path = require('path');
const dir = `/home/node/outputs/accounts/${$json.memo.account_id}/v1`;
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
fs.writeFileSync(path.join(dir, 'account_memo.json'), JSON.stringify($json.memo, null, 2));
return [{ json: $json }];

// Store v1 Agent Spec JSON
const fs = require('fs');
const path = require('path');
const dir = `/home/node/outputs/accounts/${$json.memo.account_id}/v1`;
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
fs.writeFileSync(path.join(dir, 'agent_spec.json'), JSON.stringify($json.spec, null, 2));
return [{ json: $json }];

// Extract onboarding updates and apply to v1
const content = $input.item.json.content;
const { extractFromTranscript } = require('/home/node/scripts/extract.js');
const onboardingData = await extractFromTranscript(content, 'onboarding');
// Load corresponding v1 memo
const fs = require('fs');
const v1Path = `/home/node/outputs/accounts/${onboardingData.account_id}/v1/account_memo.json`;
const v1Memo = JSON.parse(fs.readFileSync(v1Path, 'utf-8'));
const { applyOnboarding } = require('/home/node/scripts/apply-onboarding.js');
const result = await applyOnboarding(v1Memo, content);
return [{ json: result }];

// Store v2 Outputs (Memo, Spec, Changelog)
const fs = require('fs');
const path = require('path');
const dir = `/home/node/outputs/accounts/${$json.v2Memo.account_id}/v2`;
const changelogDir = `/home/node/changelog/${$json.v2Memo.account_id}`;

if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
if (!fs.existsSync(changelogDir)) fs.mkdirSync(changelogDir, { recursive: true });

fs.writeFileSync(path.join(dir, 'account_memo.json'), JSON.stringify($json.v2Memo, null, 2));
fs.writeFileSync(path.join(dir, 'agent_spec.json'), JSON.stringify($json.v2Spec, null, 2));
fs.writeFileSync(path.join(changelogDir, 'changes.json'), JSON.stringify($json.changelog, null, 2));

return [{ json: $json }];

// Update task tracker
const task = {
  task_id: `TASK-${Date.now()}`,
  account_id: $input.item.json.memo?.account_id || $input.item.json.v2Memo?.account_id,
  status: 'completed',
  timestamp: new Date().toISOString()
};
return [{ json: task }];
